1770.candidate_text:
{
    console.clear();
    displayTodoList();    
    inquirer.prompt({ 
            type: "list", 
            name: "command",
            message: "Choose option",
            choices: Object.values(Commands),
    }).then(answers => {
        switch (answers["command"]) {
            case Commands.Toggle:
                showCompleted = !showCompleted;
                promptUser();
                break;
            case Commands.Add: 
                promptAdd();
                break;
            case Commands.Complete:
                if (collection.getItemCounts().incomplete > 0) {
                    promptComplete();
                } else {
                    promptUser();
                }
                break;                
            case Commands.Purge:
                collection.removeComplete();
                promptUser();
                break;
        }
    })
}

